parameters.command:
set -euo pipefail

if [ ! -d "{work_dir}/.git" ]; then
  git clone https://github.com/{target_repo}.git {work_dir}
fi

cd {work_dir}
git fetch origin
git checkout {base_branch}
git reset --hard origin/{base_branch}
git checkout -B issue{issue_number}
if [ ! -d node_modules ]; then
  npm ci --ignore-scripts
fi
mkdir -p {artifact_dir}
rm -f {artifact_dir}/plan-evaluation.md {artifact_dir}/implementation-evaluation.md {artifact_dir}/remediate-output.txt

set -euo pipefail
# If issue was never selected, nothing to clean up
ISSUE_NUM="{issue_number}"
case "$ISSUE_NUM" in
  "{"*) echo "No issue was selected; skipping cleanup."; exit 0 ;;
  "")   echo "No issue was selected; skipping cleanup."; exit 0 ;;
esac
gh issue comment {issue_number} --repo {target_repo} --body "Luther abandoning this issue: workflow failed at step {current_step_id}."
gh issue edit {issue_number} --repo {target_repo} --remove-label "{luther_label}"
gh issue edit {issue_number} --repo {target_repo} --remove-assignee {assignee}
